// Use $input for config (from Get Config); reference trigger by name or default UI name
const config = $input.first().json;
let input;
try {
  input = $('Execute Workflow Trigger').first().json;
} catch (e) {
  input = $('When executed by another node').first().json;
}
const tierConfig = config.tiers[input.tier] || config.tiers.starter;
const amount = input.amount || (tierConfig.setupFee + tierConfig.monthlyPrice);
const closeDate = new Date();
closeDate.setDate(closeDate.getDate() + 90);
const closeDateIso = closeDate.toISOString();
const dealOwnerId = input.dealOwnerId || config.owner?.hubspotOwnerId || null;

const trim = (v) => {
  if (v === undefined || v === null) return '';
  const s = String(v).trim();
  return s;
};

const company = trim(input.company) || trim(input.company_name) || trim(input.business_name);
const first = trim(input.firstname) || trim(input.firstName);
const last = trim(input.lastname) || trim(input.lastName);
const personName = [first, last].filter(Boolean).join(' ').trim()
  || trim(input.contactName)
  || trim(input.name);
const baseLabel = company || personName;

const explicit = trim(input.dealName);
const suffixFromExplicit = explicit.includes(' - ') ? explicit.slice(explicit.indexOf(' - ')) : '';
const suffixFromField = trim(input.dealNameSuffix);
let suffix = ` - ${tierConfig.name}`;
if (suffixFromExplicit) suffix = suffixFromExplicit;
else if (suffixFromField) suffix = ` - ${suffixFromField}`;

let dealName;
if (baseLabel) {
  dealName = baseLabel + suffix;
} else if (explicit) {
  dealName = explicit;
} else {
  dealName = `${trim(input.industry) || 'New'} - ${tierConfig.name}`;
}

return [{
  json: {
    contactId: input.contactId,
    dealName,
    dealCompany: company,
    stage: input.stage || 'qualifiedtobuy',
    amount,
    industry: trim(input.industry),
    painPoint: input.painPoint || '',
    tier: input.tier || 'starter',
    closeDate: input.closeDate || closeDateIso,
    dealOwnerId: dealOwnerId ? String(dealOwnerId) : null
  }
}];

const d = $input.first().json;
const config = $('Get Config').first().json;
const pipeline = config.hubspot?.pipelineId || config.pipeline || 'default';
const stageIds = config.hubspot?.dealStageIds || {};
const rawStage = String(d.stage || 'qualifiedtobuy').trim();
const stageBuiltin = new Set(['appointmentscheduled', 'qualifiedtobuy', 'presentationscheduled', 'decisionmakerboughtin', 'contractsent', 'closedwon', 'closedlost']);
const normalizeStageToken = (s) => {
  const t = String(s || '').trim();
  if (!t) return 'qualifiedtobuy';
  if (/^[0-9]+$/.test(t)) return t;
  const lc = t.toLowerCase();
  if (stageBuiltin.has(lc)) return lc;
  return 'qualifiedtobuy';
};
const stageInput = normalizeStageToken(rawStage);

let dealstage = stageInput;
if (stageIds.leadQualified && (stageInput === 'qualifiedtobuy' || stageInput === '')) {
  dealstage = String(stageIds.leadQualified);
}

const properties = {
  dealname: d.dealName || 'New Deal',
  amount: String(d.amount),
  closedate: d.closeDate,
  dealstage,
  pipeline,
  dealtype: 'newbusiness'
};
if (d.dealOwnerId) properties.hubspot_owner_id = d.dealOwnerId;
if (d.painPoint && String(d.painPoint).trim()) properties.description = String(d.painPoint).trim();
const body = { properties };
if (d.contactId) {
  body.associations = [{ to: { id: String(d.contactId) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 3 }] }];
}
return [{ json: body }];

const res = $input.first().json;
const dealId = res.id || res.dealId;
return [{ json: { dealId, id: dealId } }];

const norm = $('Normalize Deal Response').first().json;
return [{
  json: {
    success: true,
    data: { dealId: norm.dealId },
    error: null
  }
}];

